warmup.starterCode:
class Animal:
    def __init__(self, name):
        self._name = name  # Encapsulation

    @property
    def name(self):
        return self._name

    def speak(self):  # Polymorphism hook
        return "..."

class Dog(Animal):  # Inheritance
    def speak(self):  # Polymorphism
        return "Woof!"

animals = [Animal("Generic"), Dog("Rex")]
for a in animals:
    print(f"{a.name}: {a.speak()}")
